// src/components/TourDetail.js
import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";

const TourDetail = () => {
  const { tourId } = useParams();
  const [tour, setTour] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Giả sử bạn có API lấy dữ liệu tour theo tourId
    const fetchTourDetail = async () => {
      try {
        const response = await fetch(`/api/tours/${tourId}`);
        const data = await response.json();
        setTour(data);
      } catch (error) {
        console.error("Lỗi khi fetch dữ liệu tour:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchTourDetail();
  }, [tourId]);

  if (loading) {
    return <div>Đang tải...</div>;
  }

  if (!tour) {
    return <div>Không tìm thấy thông tin chi tiết của tour.</div>;
  }

  return (
    <div className="tour-detail">
      <h2>{tour.title}</h2>
      <img src={tour.images[0]} alt={tour.title} />
      <p>{tour.description}</p>
      <ul>
        <li>Địa điểm: {tour.destination}</li>
        <li>Thời gian: {tour.time}</li>
        <li>Số lượng: {tour.quantity}</li>
        <li>Giá: {tour.priceAdult.toLocaleString("vi-VN")} VND / người</li>
      </ul>
      {/* Bạn có thể hiển thị thêm thông tin khác của tour ở đây */}
    </div>
  );
};

export default TourDetail;
